#!/usr/bin/env node
// scripts/env/generate-runtime-env.mjs
//
// Generate a runtime env file (.env/<stage>.env) FROM the tracked,
// non-secret manifest config/environments/<stage>.json (ADR-0072).
//
// The generated file is a Compose/Tilt runtime ARTIFACT only:
//   - gitignored (.env/ is ignored)
//   - reproducible (deterministic local-bootstrap secret derivation)
//   - non-authoritative (the manifest is the source of truth)
//   - safe to delete (regenerated by `make env-generate-runtime ENV=<stage>`)
//
// Secret-valued keys (SECRET_ENV_KEYS) NEVER live in the manifest. They are:
//   1. taken from .env/secrets/<stage>.env when present (written by
//      `make env-seed-secrets` from OpenBao / an external handoff), else
//   2. derived deterministically for LOCAL BOOTSTRAP from a fixed salt.
//
// Local-bootstrap secret material is reproducible and machine-independent, but
// is NOT production-grade: staging/prod values are flagged and MUST be replaced
// with OpenBao-seeded material before real exposure.
//
// Usage:
//   node scripts/env/generate-runtime-env.mjs <stage>      # one stage
//   node scripts/env/generate-runtime-env.mjs --all        # all stages
//   node scripts/env/generate-runtime-env.mjs <stage> --check   # verify up-to-date

import { createHash } from "node:crypto";
import { mkdirSync, writeFileSync, readFileSync, existsSync } from "node:fs";
import process from "node:process";
import {
  STAGES,
  STAGE_POLICY,
  SECRET_ENV_KEYS,
  loadManifest,
  loadCommon,
  generatedEnvPath,
  generatedSecretsPath,
  parseEnvFile,
  GENERATED_ENV_DIR,
} from "./lib/manifests.mjs";

// Fixed salt for LOCAL BOOTSTRAP secret derivation. This is NOT a production
// secret — it only makes local-bootstrap material reproducible across machines.
// Real environments override every value via OpenBao-seeded secret material.
const LOCAL_BOOTSTRAP_SALT = "maldous-react-local-bootstrap-v1";

// Non-sensitive local defaults that must match what the platform provisions
// (Keycloak client secrets, Grafana/test credentials). Provisioning reads the
// same generated value, so platform-api and the provisioned service always
// agree. These are derived (never hard-coded) so no secret string is committed.
const DERIVE_AS_PASSWORD = new Set([
  "KEYCLOAK_CLIENT_SECRET",
  "KEYCLOAK_PROVISIONER_CLIENT_SECRET",
  "GRAFANA_ADMIN_PASSWORD",
  "KEYCLOAK_TEST_PASSWORD",
  "SYSADMIN_BOOTSTRAP_PASSWORD",
  // Shared service credentials whose container init AND app consumer both read
  // the generated artifact, so a derived value is self-consistent.
  "MINIO_ROOT_PASSWORD",
  "KEYCLOAK_DB_PASSWORD",
  "KEYCLOAK_ADMIN_PASSWORD",
  "SENTRY_DB_PASSWORD",
]);

// CADDY_INTERNAL_SECRET is shared across environments (the react-shared Caddy
// proxies any env), so it is derived without the stage component.
const DERIVE_SHARED = new Set(["CADDY_INTERNAL_SECRET"]);

// LOCAL-BOOTSTRAP container-bootstrap passwords that must MATCH the plaintext
// already embedded in the committed connection URLs (POSTGRES_URL / DATABASE_URL,
// CLICKHOUSE_URL) — the documented Compose-bootstrap limitation (ADR-0072). Real
// environments override these via OpenBao-seeded material. These are the only
// pinned credential strings; everything else is derived.
const LOCAL_BOOTSTRAP_DEFAULTS = {
  POSTGRES_PASSWORD: "platformpassword",
  CLICKHOUSE_PASSWORD: "clickhousepassword",
};

function deriveHex(...parts) {
  return createHash("sha256").update(parts.join(":")).digest("hex");
}

// A readable strong password: hex digest sliced + a fixed symbol/case to satisfy
// typical complexity rules, deterministic for a given (stage,key).
function derivePassword(stage, key) {
  const h = deriveHex(LOCAL_BOOTSTRAP_SALT, stage, key);
  return `Bs1-${h.slice(0, 24)}`;
}

export function resolveSecrets(stage) {
  // 1. Seeded material (highest priority) — written by `make env-seed-secrets`.
  const seeded = parseEnvFile(generatedSecretsPath(stage));
  const out = {};
  let bootstrapDerived = 0;
  for (const key of SECRET_ENV_KEYS) {
    if (seeded[key] !== undefined && seeded[key] !== "") {
      out[key] = seeded[key];
      continue;
    }
    // 2. Pinned local-bootstrap default (must match committed connection URLs).
    if (LOCAL_BOOTSTRAP_DEFAULTS[key] !== undefined) {
      out[key] = LOCAL_BOOTSTRAP_DEFAULTS[key];
      bootstrapDerived++;
      continue;
    }
    // 3. Deterministic local-bootstrap derivation.
    if (DERIVE_SHARED.has(key)) {
      out[key] = deriveHex(LOCAL_BOOTSTRAP_SALT, "shared", key);
    } else if (DERIVE_AS_PASSWORD.has(key)) {
      out[key] = derivePassword(stage, key);
    } else {
      // 64-hex crypto material (encryption key, pepper, signing secret).
      out[key] = deriveHex(LOCAL_BOOTSTRAP_SALT, stage, key);
    }
    bootstrapDerived++;
  }
  return { secrets: out, seededCount: Object.keys(seeded).length, bootstrapDerived };
}

function renderEnvFile(stage, manifest, secrets, info) {
  const policy = STAGE_POLICY[stage];
  const lines = [];
  lines.push(`# .env/${stage}.env — GENERATED RUNTIME ARTIFACT — DO NOT EDIT.`);
  lines.push(`# Source of truth: config/environments/${stage}.json (ADR-0072).`);
  lines.push(`# Regenerate: make env-generate-runtime ENV=${stage}`);
  lines.push(`# This file is gitignored, reproducible, and safe to delete.`);
  lines.push(`#`);
  if (info.seededCount > 0) {
    lines.push(`# Secrets: ${info.seededCount} from seeded material (.env/secrets/${stage}.env),`);
    lines.push(`#          ${info.bootstrapDerived} derived as local-bootstrap.`);
  } else {
    lines.push(
      `# Secrets: ${info.bootstrapDerived} derived as LOCAL BOOTSTRAP (no seeded material).`
    );
  }
  if (policy.stage === "staging" || policy.stage === "production") {
    lines.push(`# WARNING: ${stage} secret material is LOCAL BOOTSTRAP and MUST be rotated`);
    lines.push(`#          (make env-seed-secrets ENV=${stage}) before any real exposure.`);
  }
  lines.push(`# NOTE: POSTGRES_URL / POSTGRES_APP_URL carry a local container-bootstrap`);
  lines.push(`#       password — the documented Compose limitation (ADR-0072). Real`);
  lines.push(`#       production must point these at an externally-managed credential.`);
  lines.push("");

  // Shared non-secret base config (common.json) merged UNDER the stage runtime —
  // stage keys win. Together they fully replace the former hand-maintained root .env.
  const common = loadCommon().runtime ?? {};
  const runtime = { ...common, ...(manifest.runtime ?? {}) };
  lines.push("# ── Non-secret bootstrap intent (common.json + manifest) ────────────────────");
  for (const [k, v] of Object.entries(runtime)) {
    lines.push(`${k}=${v}`);
  }
  lines.push("");
  lines.push("# ── Secret material (seeded from OpenBao or local-bootstrap derived) ────────");
  for (const key of SECRET_ENV_KEYS) {
    // Only emit secret keys that this stage actually uses. WEBHOOK/PEPPER/etc.
    // are always emitted; LOCAL_FIXTURE_SESSION-style keys are handled in runtime.
    lines.push(`${key}=${secrets[key]}`);
  }
  lines.push("");
  return lines.join("\n");
}

export function generate(stage) {
  if (!STAGES.includes(stage)) {
    throw new Error(`unknown stage "${stage}" (expected one of ${STAGES.join(", ")})`);
  }
  const manifest = loadManifest(stage);
  const { secrets, seededCount, bootstrapDerived } = resolveSecrets(stage);
  const content = renderEnvFile(stage, manifest, secrets, { seededCount, bootstrapDerived });
  return { content, path: generatedEnvPath(stage) };
}

function writeStage(stage) {
  const { content, path } = generate(stage);
  mkdirSync(GENERATED_ENV_DIR, { recursive: true });
  writeFileSync(path, content, { mode: 0o600 });
  return path;
}

function checkStage(stage) {
  const { content, path } = generate(stage);
  if (!existsSync(path)) return { ok: false, reason: "missing" };
  const current = readFileSync(path, "utf8");
  return { ok: current === content, reason: current === content ? "up-to-date" : "stale" };
}

function main() {
  const args = process.argv.slice(2);
  const check = args.includes("--check");
  const all = args.includes("--all");
  const stageArg = args.find((a) => !a.startsWith("--")) ?? process.env.ENV ?? "dev";
  const stages = all ? STAGES : [stageArg];

  let failures = 0;
  for (const stage of stages) {
    if (check) {
      const r = checkStage(stage);
      if (r.ok) {
        console.log(`  ✓ ${stage}: ${r.reason}`);
      } else {
        console.error(
          `  ✗ ${stage}: generated env ${r.reason} — run: make env-generate-runtime ENV=${stage}`
        );
        failures++;
      }
    } else {
      const path = writeStage(stage);
      console.log(`  ✓ generated ${path.replace(process.cwd() + "/", "")}`);
    }
  }
  if (failures > 0) process.exit(1);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  main();
}
